class Solution {
public:
    int maxStability(int n, vector<vector<int>>& edges, int k) {
        vector<vector<int>> graph(n);
        for (auto& edge : edges) {
            graph[edge[0]].push_back({edge[1], edge[2], edge[3]});
            graph[edge[1]].push_back({edge[0], edge[2], edge[3]});
        }
        vector<int> dp(1 << n, INT_MAX);
        dp[0] = 0;
        for (int mask = 1; mask < (1 << n); mask++) {
            for (int i = 0; i < n; i++) {
                if (!(mask & (1 << i))) continue;
                for (auto& neighbor : graph[i]) {
                    if (!(mask & (1 << neighbor.first))) continue;
                    if (neighbor.second == 1) {
                        dp[mask] = min(dp[mask], dp[mask ^ (1 << i)] + neighbor.second);
                    } else if (k > 0) {
                        dp[mask] = min(dp[mask], dp[mask ^ (1 << i)] + neighbor.second * 2);
                        k--;
                    }
                }
            }
        }
        int res = INT_MAX;
        for (int mask = (1 << n) - 1; mask >= 0; mask--) {
            if (dp[mask] < res) res = dp[mask];
        }
        return res == INT_MAX ? -1 : res;
    }
};
